section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/mocking-strategies",
  "type": "array",
  "items": {
    "type": "object",
    "required": ["collaborator", "doubleType", "patchTarget", "rationale"],
    "properties": {
      "collaborator": {"type": "string"},
      "doubleType": {"enum": ["dummy", "stub", "spy", "mock", "fake"]},
      "patchTarget": {"type": "string", "description": "Module path where the name is looked up."},
      "isAsync": {"type": "boolean"},
      "rationale": {"type": "string", "minLength": 15}
    }
  }
}

example.code:
[
  {
    "collaborator": "stripe.PaymentIntent.create",
    "doubleType": "stub",
    "patchTarget": "app.checkout.stripe",
    "isAsync": false,
    "rationale": "We only need a deterministic return; call signature is not under test."
  },
  {
    "collaborator": "user_repo.get",
    "doubleType": "fake",
    "patchTarget": "app.users.user_repo",
    "isAsync": true,
    "rationale": "Repository interface stable; in-memory fake is faster than mock setup."
  }
]
